from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta
import secrets
import hashlib
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = os.getenv('DATABASE_URL', 'sqlite:///app.db')
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://"
)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(255), nullable=False)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token_hash = db.Column(db.String(255), unique=True, nullable=False)
    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False, nullable=False)

with app.app_context():
    db.create_all()

def send_reset_email(email, token):
    smtp_server = os.getenv('SMTP_SERVER', 'localhost')
    smtp_port = int(os.getenv('SMTP_PORT', 587))
    smtp_user = os.getenv('SMTP_USER', '')
    smtp_password = os.getenv('SMTP_PASSWORD', '')
    from_email = os.getenv('FROM_EMAIL', 'noreply@example.com')
    
    reset_link = f"{os.getenv('BASE_URL', 'http://localhost:5000')}/reset-password?token={token}"
    
    msg = MIMEMultipart('alternative')
    msg['Subject'] = 'Password Reset Request'
    msg['From'] = from_email
    msg['To'] = email
    
    text = f"Click the following link to reset your password: {reset_link}\n\nThis link expires in 1 hour."
    html = f"<p>Click the following link to reset your password:</p><p><a href='{reset_link}'>Reset Password</a></p><p>This link expires in 1 hour.</p>"
    
    part1 = MIMEText(text, 'plain')
    part2 = MIMEText(html, 'html')
    msg.attach(part1)
    msg.attach(part2)
    
    try:
        with smtplib.SMTP(smtp_server, smtp_port) as server:
            if smtp_port == 587:
                server.starttls()
            if smtp_user and smtp_password:
                server.login(smtp_user, smtp_password)
            server.send_message(msg)
    except Exception:
        pass

@app.route('/api/password-reset/request', methods=['POST'])
@limiter.limit("3 per hour")
def request_password_reset():
    data = request.get_json()
    
    if not data or 'email' not in data:
        return jsonify({'message': 'If an account exists with this email, a password reset link has been sent.'}), 200
    
    email = data['email'].strip().lower()
    
    if not email or len(email) > 120:
        return jsonify({'message': 'If an account exists with this email, a password reset link has been sent.'}), 200
    
    user = User.query.filter_by(email=email).first()
    
    if user:
        PasswordResetToken.query.filter_by(user_id=user.id, used=False).filter(
            PasswordResetToken.expires_at > datetime.utcnow()
        ).update({'used': True})
        db.session.commit()
        
        token = secrets.token_urlsafe(32)
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        
        reset_token = PasswordResetToken(
            user_id=user.id,
            token_hash=token_hash,
            expires_at=datetime.utcnow() + timedelta(hours=1)
        )
        
        db.session.add(reset_token)
        db.session.commit()
        
        send_reset_email(email, token)
    
    return jsonify({'message': 'If an account exists with this email, a password reset link has been sent.'}), 200

@app.route('/api/password-reset/verify', methods=['POST'])
@limiter.limit("10 per hour")
def verify_reset_token():
    data = request.get_json()
    
    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({'message': 'Invalid or expired reset token.'}), 400
    
    token = data['token']
    new_password = data['new_password']
    
    if not new_password or len(new_password) < 8:
        return jsonify({'message': 'Password must be at least 8 characters long.'}), 400
    
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    
    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).filter(
        PasswordResetToken.expires_at > datetime.utcnow()
    ).first()
    
    if not reset_token:
        return jsonify({'message': 'Invalid or expired reset token.'}), 400
    
    user = User.query.get(reset_token.user_id)
    
    if not user:
        return jsonify({'message': 'Invalid or expired reset token.'}), 400
    
    user.password_hash = hashlib.sha256(new_password.encode()).hexdigest()
    reset_token.used = True
    
    db.session.commit()
    
    return jsonify({'message': 'Password has been reset successfully.'}), 200

if __name__ == '__main__':
    app.run(debug=False)